        function cekemailweb1(){
            // alert("WOOOYYYY BAHLUL ENTE");
            var vEmail = document.getElementById("email").value;

            // alert(vEmail);
            $.ajax({
                type  : 'get',
                url   : '<?php echo base_url()?>index.php/Seminar/cek_email_peserta1/'+vEmail, 
                async : false,
                dataType : 'json',
                oLanguage: {
                  sProcessing: "loading ..."
                },
                processing : true,
         
         
                // "serverSide": true,
                success : function(data){
                    var html = '';
                    var i;
                    // alert(data.length);
                    if (data.length != 0) {
                        for(i=0; i<data.length; i++){

                        var CEK = data[i].Name;
                          
                        document.getElementById("txtWebinar5Name").value = data[i].Name;
                        $("#btndownload").show();
                        $("#txtWebinar5Name").show();
                        $("#email").hide();
                        $("#ckemail").hide();
                        $("#refresh").show();
                          
                        }
                    }else{
                        $("#alert").show();
                    }
                }

            });

            
        }

