        var downloadCertificate1 = function (imgData, name, x, y, filename) {
            var doc = new jsPDF('l', 'mm', 'a4')
            doc.addImage(imgData, "PNG", 0, 0, 297, 210);
            doc.setFontSize(36);

            doc.setFont('Times', 'bolditalic')
            doc.text(name, 150, 84, { align: 'center' });
            doc.save(name + filename);
            console.log('Generated certificate for ', name)
        }

